    const particles = document.getElementById('particles');
    for(let i=0;i<34;i++){
      const p=document.createElement('div');
      p.className='particle';
      const size=Math.random()*4+2;
      p.style.width=size+'px';
      p.style.height=size+'px';
      p.style.left=Math.random()*100+'%';
      p.style.top=(Math.random()*100+10)+'%';
      p.style.animationDuration=(8+Math.random()*10)+'s';
      p.style.animationDelay=(-Math.random()*10)+'s';
      p.style.opacity=(0.18+Math.random()*0.45);
      particles.appendChild(p);
    }

    const revealEls = document.querySelectorAll('.reveal');
    const metricEls = document.querySelectorAll('.metric');
    let metricsAnimated = false;

    const obs = new IntersectionObserver((entries)=>{
      entries.forEach(entry=>{
        if(entry.isIntersecting){
          entry.target.classList.add('visible');

          if(entry.target.classList.contains('problem-card')){
            entry.target.classList.add('visible');
          }

          if(entry.target.classList.contains('metric') && !metricsAnimated){
            animateMetrics();
            metricsAnimated = true;
          }
        }
      });
    }, {threshold:0.18});

    revealEls.forEach(el=>obs.observe(el));

    function animateValue(el, end, decimals, duration=1600){
      const start = 0;
      const startTime = performance.now();
      function tick(now){
        const progress = Math.min((now-startTime)/duration,1);
        const eased = 1 - Math.pow(1-progress,3);
        const val = start + (end-start)*eased;
        el.textContent = decimals > 0
          ? val.toFixed(decimals)
          : Math.round(val).toLocaleString();
        if(progress < 1) requestAnimationFrame(tick);
      }
      requestAnimationFrame(tick);
    }

    function animateMetrics(){
      metricEls.forEach((metric, i)=>{
        const valueEl = metric.querySelector('.value');
        const target = parseFloat(metric.dataset.target);
        const decimals = parseInt(metric.dataset.decimals || '0', 10);
        setTimeout(()=>animateValue(valueEl, target, decimals, 1500), i*140);
      });
    }
  </script>
